const express = require('express');
const router = express.Router();
const { getProjectById } = require('./service');

router.get('/:projectId', async (req, res) => {
  const project = await getProjectById(req.params.projectId);
  if (!project) return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  res.json({ project });
});

module.exports = router;

const { getProjectById } = require('./routes');
const projects = {};

export function addProject(id, name) {
  projects[id] = { id, name };
}

export function getAllProjects() {
  return Object.values(projects);
}

export async function getProjectById(id) {
  if (!projects[id]) return null;
  return projects[id];
}

const express = require('express');
const router = express.Router();
const { addMember } = require('./service');

router.post('/:projectId/members', async (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BAD_REQUEST', 'Invalid member data');
  const member = await addMember(req.params.projectId, req.body);
  res.status(201).json({ member });
});

module.exports = router;

const express = require('express');
const router = express.Router();
const { updateTaskStatus, getTasksByStatus } = require('./service');

router.patch('/:projectId/tasks/:taskId', async (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid task status');
  const updatedTask = await updateTaskStatus(req.params.taskId, req.body.status);
  res.json({ task: updatedTask });
});

router.get('/:projectId/tasks', async (req, res) => {
  const tasks = await getTasksByStatus(req.params.projectId, req.query.status);
  res.json({ tasks });
});

module.exports = router;

